import cloud.hetzner.api.HetznerCloudApiClient;
import cloud.hetzner.api.http.client.HttpProxyConfiguration;

HetznerCloudApiClient client = new HetznerCloudApiClient.Builder()
  .httpClientConfig(configBuilder -> configBuilder
      .proxyConfig(new HttpProxyConfiguration.Builder("http://localhost",
          8080).auth("username", "password")))
  .build();

import java.io.IOException;
import cloud.hetzner.api.exceptions;

exampleController.getExampleTypeAsync(body).thenAccept(result -> {
    // success callback handler
    System.out.println("Success! Result: " + result.getResult());
    System.out.println("Status Code: " + result.getStatusCode());
    System.out.println("Response Headers: " + result.getHeaders());
}).exceptionally(exception -> {
    Throwable cause = exception.getCause() != null ? exception.getCause() : exception;

    if (cause instanceof ApiException) {
        ApiException apiException = (ApiException) cause;
        System.out.println("Error: " + apiException.getMessage());
        System.out.println("Result: " + apiException.getHttpContext()
            .getResponse()
            .getBody());
        System.out.println("Status Code: " + apiException.getResponseCode());

    } else if (cause instanceof IOException) {
        IOException ioException = (IOException) cause;
        System.out.println("IO Error: " + ioException.getMessage());

    } else {
        cause.printStackTrace();
    }

    return null;
});
